#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
apply_collaboration_phase2.py — Module collaboration DWG Bilnov, PHASES 2 & 3.

Front commentaires-fiches (formulaire, marqueurs colores par statut, panneau
lateral, discussion, historique, pieces jointes), persistance des mesures,
unite par projet, notifications (cloche), rapport PDF imprimable, droits fins
(§17) et partage filtre des commentaires (§14).

Necessite la Phase 1 deja appliquee. A lancer a la racine du repo (Codespace) :
    python3 apply_collaboration_phase2.py
Ecrit le code -> prisma generate -> prisma db push (additif) -> next build
(STOP si echec, rien n'est pousse) -> commit + push.
"""
import base64, json, os, subprocess, sys
FILES = json.loads(r'''{
"prisma/schema.prisma": "",
"src/lib/access.ts": "",
"src/lib/cadStatus.ts": "",
"src/components/CadViewer.tsx": "",
"src/components/NotificationsBell.tsx": "",
"src/app/dashboard/page.tsx": "",
"src/app/api/files/[id]/comments/route.ts": "",
"src/app/api/files/[id]/comments/[cid]/route.ts": "",
"src/app/api/files/[id]/comments/[cid]/replies/route.ts": "",
"src/app/api/files/[id]/comments/[cid]/attachments/[attId]/route.ts": "",
"src/app/api/files/[id]/measurements/route.ts": "",
"src/app/api/projects/[id]/members/[memberId]/route.ts": "",
"src/app/api/projects/[id]/access-codes/route.ts": "",
"src/app/api/shared/[id]/files/[fileId]/comments/route.ts": ""
}''')

def run(*a, check=True):
    print("+"," ".join(a)); return subprocess.run(a, check=check)
def cfg(k):
    return subprocess.run(["git","config",k],capture_output=True,text=True).stdout.strip()

def main():
    if not os.path.isfile("package.json") or not os.path.isdir("prisma"):
        sys.exit("ERREUR: lance ce script a la racine du repo bilnov-app.")
    if not os.path.isfile("src/lib/cadComments.ts"):
        sys.exit("ERREUR: la Phase 1 doit etre appliquee d'abord (src/lib/cadComments.ts absent).")
    for path,b64 in FILES.items():
        os.makedirs(os.path.dirname(path),exist_ok=True)
        open(path,"wb").write(base64.b64decode(b64)); print("  ecrit:",path)
    run("npx","prisma","generate")
    print(">>> Synchronisation base (prisma db push, additif)...")
    run("npx","prisma","db","push")
    print(">>> Verification build...")
    if run("npx","next","build",check=False).returncode != 0:
        sys.exit("!!! next build a ECHOUE : rien n'est pousse. Corrige puis relance.")
    if not cfg("user.email"): run("git","config","user.email","bilnov-bot@users.noreply.github.com")
    if not cfg("user.name"):  run("git","config","user.name","BILNOV bot")
    run("git","add","-A")
    run("git","commit","-m","feat(cad): module collaboration Phases 2-3 (front commentaires, mesures persistees, unite projet, notifications, rapport PDF, droits fins, partage filtre)")
    run("git","push")
    print("\nOK. Build verifie, base synchronisee, push sur main -> Vercel deploie.")

if __name__ == "__main__":
    main()
